Below is a complete, single-file solution using **HTML and JavaScript with the Three.js library**.

### How to view this:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #f0f8ff; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            font-family: sans-serif;
            color: #333;
            pointer-events: none;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <div id="info">Left Click to Rotate | Right Click to Pan | Scroll to Zoom</div>

    <!-- Load Three.js from CDN -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <!-- Load OrbitControls -->
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>

    <script>
        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue

        // Add some fog for depth
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(10, 10, 10);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. Controls (Mouse interaction)
        const controls = new THREE.OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const grassMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8b4513 }); // Brown roof
        const woodMat = new THREE.MeshStandardMaterial({ color: 0xdeb887 }); // Wooden frame details

        // Group to hold the whole house
        const houseGroup = new THREE.Group();
        scene.add(houseGroup);

        // --- Building the House Parts ---

        // A. Ground (Grass)
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, grassMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. Main Base Structure
        const baseGeo = new THREE.BoxGeometry(8, 5, 8);
        const mainBody = new THREE.Mesh(baseGeo, wallMat);
        mainBody.position.y = 2.5; // Sit on top of ground
        mainBody.castShadow = true;
        mainBody.receiveShadow = true;
        houseGroup.add(mainBody);

        // C. Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(5.5, 4, 4); // 4 sides
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 7; // Center of cone is at y=7 (height/2), total height 11
        roof.rotation.y = Math.PI / 4; 
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Front Door
        const doorGeo = new THREE.BoxGeometry(2, 3.5, 0.5);
        const door = new THREE.Mesh(doorGeo, woodMat);
        door.position.set(-1.5, 1.75, 4); // X, Y, Z relative to main body (which is at 0,0)
        door.castShadow = true;
        houseGroup.add(door);

        // E. Window (Simple Hole logic via Mesh)
        const winFrameGeo = new THREE.BoxGeometry(2, 1.5, 0.2);
        const winGlassGeo = new THREE.BoxGeometry(1.9, 1.3, 0.05);

        // Frame
        const window = new THREE.Mesh(winFrameGeo, woodMat);
        window.position.set(1.5, 3, 4);
        houseGroup.add(window);

        // Glass pane
        const glass = new THREE.Mesh(winGlassGeo, new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.6 }));
        glass.position.set(1.5, 3, 4.1); // Slightly offset to sit inside frame visually
        houseGroup.add(glass);

        // F. Chimney
        const chimGeo = new THREE.BoxGeometry(1, 4, 1);
        const chimney = new THREE.Mesh(chimGeo, roofMat);
        chimney.position.set(0, 9.5, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);


        // 5. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update(); // required if damping is enabled
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
